<?php/** * WooCommerce compatibility functions * * @package AquaLuxe * @since 1.0.0 */// Exit if accessed directlyif (!defined('ABSPATH')) {    exit;}/** * Initialize WooCommerce support */function aqualuxe_woocommerce_setup() {    // Add theme support for WooCommerce    add_theme_support('woocommerce');        // Add support for WooCommerce product gallery features    add_theme_support('wc-product-gallery-zoom');    add_theme_support('wc-product-gallery-lightbox');    add_theme_support('wc-product-gallery-slider');        // Declare WooCommerce support    add_theme_support('woocommerce', array(        'thumbnail_image_width' => 400,        'single_image_width' => 800,        'product_grid' => array(            'default_rows' => 3,            'min_rows' => 1,            'max_rows' => 8,            'default_columns' => 4,            'min_columns' => 1,            'max_columns' => 6,        ),    ));}add_action('after_setup_theme', 'aqualuxe_woocommerce_setup');